def _merge_url(self, url: URL | str) -> URL:
    """
    Merge a URL argument together with any 'base_url' on the client,
    to create the URL used for the outgoing request.
    """
    merge_url = URL(url)
    if merge_url.is_relative_url:
        merge_raw_path = self.base_url.raw_path + merge_url.raw_path.lstrip(b"/")
        # Preserve query params: use merge URL's query if present,
        # otherwise keep the base URL's query string.
        if merge_url.raw_path.find(b"?") != -1:
            return self.base_url.copy_with(raw_path=merge_raw_path)
        query = self.base_url.query
        merged = self.base_url.copy_with(raw_path=merge_raw_path)
        if query:
            return URL(str(merged) + "?" + str(query))
        return merged
    return merge_url

def _build_auth_header(self, username: str | bytes, password: str | bytes) -> str:
    username_bytes = to_bytes(username)
    if b":" in username_bytes:
        raise ValueError(
            "Username must not contain a colon character ':' "
            "(see RFC 7617, Section 2)."
        )
    userpass = b":".join((username_bytes, to_bytes(password)))
    token = b64encode(userpass).decode()
    return f"Basic {token}"
